import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebService;
import java.math.BigDecimal;

@WebService(name = "OrderProcessingService", targetNamespace = "http://ecommerce.com/order")
public class OrderProcessingService {

    @WebMethod(operationName = "processOrder")
    public String processOrder(@WebParam(name = "orderDetails") OrderDetails orderDetails) {
        BigDecimal totalPrice = calculateTotalPrice(orderDetails);
        if (totalPrice != null) {
            // Process the order
            return "Order processed successfully. Total Price: " + totalPrice;
        } else {
            return "Failed to process order.";
        }
    }

    private BigDecimal calculateTotalPrice(OrderDetails orderDetails) {
        BigDecimal total = BigDecimal.ZERO;
        for (Item item : orderDetails.getItems()) {
            BigDecimal itemTotal = item.getPrice().multiply(new BigDecimal(item.getQuantity()));
            total = total.add(itemTotal);
        }
        return total;
    }
}

class OrderDetails {
    private Item[] items;

    public Item[] getItems() {
        return items;
    }

    public void setItems(Item[] items) {
        this.items = items;
    }
}

class Item {
    private BigDecimal price;
    private int quantity;

    public BigDecimal getPrice() {
        return price;
    }

    public void setPrice(BigDecimal price) {
        this.price = price;
    }

    public int getQuantity() {
        return quantity;
    }

    public void setQuantity(int quantity) {
        this.quantity = quantity;
    }
}